mapper.insert:
INSERT INTO sys_login_log (
    id, username, ip, location, browser, os, status, msg,
    tenant_id, created_by, created_time, updated_by, updated_time, deleted, version
) VALUES (
    #{id}, #{username}, #{ip}, #{location}, #{browser}, #{os}, #{status}, #{msg},
    #{tenantId}, #{createdBy}, #{createdTime}, #{updatedBy}, #{updatedTime}, #{deleted}, #{version}
)

mapper.select:
SELECT FROM sys_login_log WHERE deleted = FALSE
AND username LIKE CONCAT('%', #{username}, '%')
AND status = #{status}
AND created_time >= CAST(#{startTime} AS TIMESTAMP)
AND created_time < CAST(#{endTime} AS TIMESTAMP) + INTERVAL '1 day'
ORDER BY created_time DESC LIMIT #{pageSize} OFFSET #{offset}
